Bash(paixueji/object_prompts.json <<'EOF'
{
  "level1_categories": {
    "foods": {
      "prompt": "When talking about foods, focus on taste, color, texture, smell, and where the food comes from. Discuss if it gives energy, helps grow strong, or is a special treat. Ask simple questions about sweetness, crunchiness, hot or cold, and whether it grows on plants or comes from animals."
    },
    "animals": {
      "prompt": "When discussing animals, focus on body covering, movement, habitat, diet, sounds, and baby care. Ask about colors, sizes, what they eat, where they sleep, and whether they live alone or in groups."
    },
    "plants": {
      "prompt": "When talking about plants, focus on roots, stems, leaves, flowers, fruits, and seeds. Discuss what plants need to grow, how they drink water, make food with sunlight, and change with seasons."
    }
  },
  "level2_categories": {
    "fresh_ingredients": {
      "prompt": "For fresh ingredients, emphasize that they come straight from farms, gardens, trees, or animals and are usually eaten soon after picking. Discuss keeping them cold, their natural smells, and healthy nutrients.",
      "parent": "foods"
    },
    "processed_foods": {
      "prompt": "For processed foods, focus on how people change, mix, cook, or package ingredients in factories or kitchens to make them last longer or taste different. Discuss everyday foods versus occasional treats.",
      "parent": "foods"
    },
    "beverages_drinks": {
      "prompt": "For drinks and beverages, focus on taste, temperature, color, and whether they quench thirst or give quick energy. Discuss water-based, milk-based, or sweet drinks and which ones are best for growing bodies.",
      "parent": "foods"
    },
    "vertebrates": {
      "prompt": "For vertebrate animals, emphasize the backbone inside the body, different coverings, warm or cold blood, and ways of breathing. Discuss strong bones that help them run, swim, fly, or walk upright.",
      "parent": "animals"
    },
    "invertebrates": {
      "prompt": "For invertebrate animals, focus on soft bodies or hard outer shells, many legs or no legs, special ways of moving, and clever survival tricks without a backbone.",
      "parent": "animals"
    },
    "human_raised_animals": {
      "prompt": "For animals raised by people, focus on how humans provide food, shelter, and care. Discuss pets that live in homes and farm animals that give milk, eggs, wool, or help with work.",
      "parent": "animals"
    },
    "ornamental_plants": {
      "prompt": "For ornamental plants grown for beauty, focus on colorful flowers, pretty leaves, and pleasant scents. Discuss growing them in pots, gardens, or bouquets just to make people happy.",
      "parent": "plants"
    },
    "useful_plants": {
      "prompt": "For useful plants, emphasize edible parts, herbs for flavor or medicine, fibers for clothes, or wood for building. Discuss how people plant and harvest them on purpose.",
      "parent": "plants"
    },
    "wild_natural_plants": {
      "prompt": "For wild plants that grow without human help, focus on natural seed spreading, survival in forests or fields, and roles in feeding wild animals or protecting soil.",
      "parent": "plants"
    }
  }
}
EOF)
